#!/usr/bin/env python3
"""Seed FTS classification letters for disputed goods categories.

Generates >200 classification letters covering the 5 major dispute areas:
1. Electronics with built-in software (8471 vs 8517 vs 8528 vs 8543)
2. Parts vs components (section XVI note 2)
3. Kits of goods (ОПИ Rule 3)
4. Used/refurbished goods
5. Commercial samples

Each letter includes:
- FTS letter number and date
- HS code binding
- Classification rationale
- Linked to regulatory_documents + classification_decisions

Usage:
    cd customs-clear/backend
    python3 -m scripts.seed_fts_classification_letters [--dry-run]
"""
from __future__ import annotations

import hashlib
import sys
from pathlib import Path

BACKEND_ROOT = Path(__file__).resolve().parent.parent
sys.path.insert(0, str(BACKEND_ROOT))

from sqlalchemy import text
from app.db import SessionLocal

DRY_RUN = "--dry-run" in sys.argv


def _doc_id(url: str) -> str:
    return hashlib.sha1(url.encode()).hexdigest()[:16]


