ALL_LETTERS = ELECTRONICS_LETTERS + PARTS_LETTERS + KITS_LETTERS + USED_GOODS_LETTERS + SAMPLES_LETTERS + ADDITIONAL_LETTERS + FOOD_PHARMA_LETTERS


def _category_for_letter(num: str) -> str:
    prefix = num.split("/")[1][:2]
    return {
        "12": "electronics_software",
        "22": "parts_vs_components",
        "33": "kits_of_goods",
        "44": "used_goods",
        "55": "commercial_samples",
        "66": "cross_cutting",
        "77": "food_pharma",
    }.get(prefix, "other")


def seed() -> dict[str, int]:
    stats = {"reg_docs": 0, "cls_decisions": 0, "hs_mappings": 0}

    with SessionLocal() as db:
        for letter in ALL_LETTERS:
            num = letter["num"]
            url = f"https://customs.gov.ru/document/letter/{num.replace('/', '-')}"
            doc_id = _doc_id(url)
            hs = letter["hs"]
            category = _category_for_letter(num)

            # Insert into regulatory_documents
            exists = db.execute(
                text("SELECT 1 FROM regulatory_documents WHERE id = :id"),
                {"id": doc_id},
            ).fetchone()
            if not exists:
                db.execute(text(
                    "INSERT INTO regulatory_documents "
                    "(id, title, agency, doc_type, doc_number, doc_date, source_url, "
                    "summary, status, quality) "
                    "VALUES (:id, :title, 'FTS', 'letter', :doc_num, :date, :url, "
                    ":summary, 'active', 'normal')"
                ), {
                    "id": doc_id,
                    "title": f"Письмо ФТС № {num}: {letter['title']}",
                    "doc_num": num,
                    "url": url,
                    "date": letter["date"],
                    "summary": letter["rationale"][:500],
                })
                stats["reg_docs"] += 1

            # Insert HS mapping (if valid HS code)
            if hs != "0000000000":
                hs_prefix = hs[:4]
                map_exists = db.execute(
                    text("SELECT 1 FROM regulatory_doc_hs_mapping WHERE doc_id = :did AND hs_prefix = :hp"),
                    {"did": doc_id, "hp": hs_prefix},
                ).fetchone()
                if not map_exists:
                    db.execute(text(
                        "INSERT INTO regulatory_doc_hs_mapping (doc_id, hs_prefix) VALUES (:did, :hp)"
                    ), {"did": doc_id, "hp": hs_prefix})
                    stats["hs_mappings"] += 1

            # Insert into classification_decisions
            dec_exists = db.execute(
                text("SELECT 1 FROM classification_decisions WHERE decision_number = :dn"),
                {"dn": f"FTS-{num}"},
            ).fetchone()
            if not dec_exists and hs != "0000000000":
                db.execute(text(
                    "INSERT INTO classification_decisions "
                    "(hs_code, product_name, description, decision_number, issue_date, target_entity) "
                    "VALUES (:hs, :name, :desc, :num, :date, :cat)"
                ), {
                    "hs": hs,
                    "name": letter["title"],
                    "desc": letter["rationale"],
                    "num": f"FTS-{num}",
                    "date": letter["date"],
                    "cat": category,
                })
                stats["cls_decisions"] += 1

        if DRY_RUN:
            db.rollback()
            print(f"[DRY RUN] Would insert: {stats}")
        else:
            db.commit()
            print(f"Inserted: {stats}")

        total_letters = len(ALL_LETTERS)
        print(f"Total classification letters: {total_letters}")
        print(f"  Electronics (8471 vs 8517): {len(ELECTRONICS_LETTERS)}")
        print(f"  Parts vs components: {len(PARTS_LETTERS)}")
        print(f"  Kits of goods: {len(KITS_LETTERS)}")
        print(f"  Used/refurbished: {len(USED_GOODS_LETTERS)}")
        print(f"  Commercial samples: {len(SAMPLES_LETTERS)}")
        print(f"  Cross-cutting: {len(ADDITIONAL_LETTERS)}")

    return stats


if __name__ == "__main__":
    seed()
